mapper.select:
SELECT tenant_id, business_context, summary_date, currency,
       order_count, total_amount, last_event_at
FROM daily_order_summary
WHERE tenant_id = #{tenantId}
  AND summary_date >= #{fromDate}
  AND summary_date <= #{toDate}

    AND business_context = #{businessContext}

ORDER BY summary_date, business_context, currency
